import{v as i}from"./chunk-WNOJSWXP.js";var r=[{id:"drinks",label:"Drinks",icon:"local_cafe",description:"Handcrafted teas & coffees"},{id:"breakfast",label:"Breakfast",icon:"breakfast_dining",description:"Made-fresh Indian breakfast"},{id:"maggi",label:"Maggi",icon:"ramen_dining",description:"Comfort in a bowl"},{id:"sandwich",label:"Sandwich",icon:"lunch_dining",description:"Grilled to perfection"},{id:"pasta",label:"Pasta",icon:"restaurant",description:"Velvety, warm, satisfying"}],s=[{id:"lemon-chai",name:"Lemon Chai",price:15,category:"drinks",description:"A zesty blend of tea and fresh lemon \u2014 light and refreshing.",image:"/assets/images/lemon-chai.webp"},{id:"chai",name:"Chai",price:20,category:"drinks",description:"Our classic milk tea \u2014 simple, warm, comforting.",image:"/assets/images/chai.webp",tag:"bestseller"},{id:"masala-chai",name:"Masala Chai",price:25,category:"drinks",description:"Spiced tea brewed with ginger, cardamom, and freshly ground spices.",image:"/assets/images/masala-chai.webp",tag:"bestseller",cookingTime:"10-12 minutes",chefTips:"Always add spices to hot water first, then tea leaves. Finish with a dash of ginger juice for extra warmth.",ingredients:[{name:"Assam Tea Leaves",source:"Assam, India",farmName:"Brahmaputra Valley Tea Estate",funFact:"Assam tea is known for its malty, robust flavor and is harvested 3 times per year.",season:"Year-round"},{name:"Green Cardamom",source:"Kerala, India",farmName:"Wayanad Cardamom Farms",funFact:"Cardamom is the third most expensive spice in the world after saffron and vanilla.",season:"Monsoon season"},{name:"Fresh Ginger",source:"Uttarakhand, India",farmName:"Organic Ginger Farms, Dehradun",funFact:"Ginger has been used in traditional medicine for over 5,000 years.",season:"Winter months"},{name:"Cinnamon",source:"Sri Lanka",farmName:"Ceylon Cinnamon Plantations",funFact:"True cinnamon (Ceylon) is different from cassia and has a sweeter, more delicate flavor.",season:"Year-round"},{name:"Fresh Milk",source:"Local Dehradun Dairy",farmName:"Happy Cows Dairy, Dehradun",funFact:"We source milk from cows that graze on Himalayan foothill grasses.",season:"Year-round"}],productionStory:[{id:1,title:"Selecting Premium Tea Leaves",subtitle:"From the gardens of Assam",description:"Our tea journey begins in the lush tea gardens of Assam, where tea leaves are handpicked at dawn. Only the youngest, most tender leaves and buds are selected for our Masala Chai. These leaves will give our chai its signature robust, malty flavor that my customers love.",image:"/assets/images/production/tea-garden.jpg",stepNumber:1,totalSteps:6,duration:"2 hours harvesting",tips:["Leaves picked at dawn have the best flavor profile","Second flush leaves (May-July) produce the most robust chai"]},{id:2,title:"Preparing the Spice Blend",subtitle:"Freshly ground aromatic spices",description:"While the tea leaves rest, we prepare our signature spice blend. Fresh cardamom pods are crushed, cinnamon is barked, and ginger is grated by hand. No pre-ground spices here \u2014 everything is freshly prepared to capture maximum aroma and essential oils.",image:"/assets/images/production/spice-prep.jpg",stepNumber:2,totalSteps:6,duration:"15 minutes preparation",tips:["Crush cardamom just before use to preserve essential oils","Grate ginger finely for even flavor distribution"]},{id:3,title:"Releasing the Aromatics",subtitle:"Blooming the spices in water",description:"We start by boiling water with whole spices. As the water reaches a rolling boil, the spices release their essential oils, coloring the water golden and filling the kitchen with an unforgettable aroma. This is where the magic begins.",image:"/assets/images/production/spice-bloom.jpg",stepNumber:3,totalSteps:6,duration:"3-4 minutes",tips:["Use fresh water \u2014 never reboiled water for tea","Let spices simmer uncovered to concentrate aromas"]},{id:4,title:"Adding Tea Leaves",subtitle:"The perfect brew",description:"Now comes the tea leaves. We add them to the spiced water and let them steep for exactly 2 minutes. Not too long (bitter), not too short (weak). The water turns a beautiful amber-red color, telling us the tea is perfectly brewed.",image:"/assets/images/production/tea-steeping.jpg",stepNumber:4,totalSteps:6,duration:"2 minutes",tips:["Never squeeze tea leaves \u2014 releases tannins that cause bitterness","Perfect steeping time is between 90 seconds and 2 minutes"]},{id:5,title:"Adding Milk & Sugar",subtitle:"Creamy sweetness to balance",description:'Fresh, cold milk is poured in \u2014 we use full-cream for the creamiest texture. Sugar is added to taste (usually 1-2 teaspoons per glass). The mixture comes to a gentle boil again, creating that frothy layer we call "chhaya" that gives chai its signature look.',image:"/assets/images/production/milk-addition.jpg",stepNumber:5,totalSteps:6,duration:"2-3 minutes",tips:["Use cold milk to prevent curdling when added to hot tea","Do not boil vigorously after adding milk \u2014 gentle simmer only"]},{id:6,title:"Straining & Serving",subtitle:"Fresh chai, ready to enjoy",description:"Finally, we strain the chai into a pre-warmed glass or kulhad. The liquid is perfectly balanced between tea, milk, and spices. Served piping hot with ladoo or biscuits on the side. This is Masala Chai \u2014 a cup of comfort made with love.",image:"/assets/images/masala-chai.webp",stepNumber:6,totalSteps:6,duration:"1 minute",tips:["Pre-warm serving vessel for best experience","Serve immediately \u2014 chai waits for no one!"]}],rotationImages:["/assets/images/360/masala-chai/angle-0.jpg","/assets/images/360/masala-chai/angle-30.jpg","/assets/images/360/masala-chai/angle-60.jpg","/assets/images/360/masala-chai/angle-90.jpg","/assets/images/360/masala-chai/angle-120.jpg","/assets/images/360/masala-chai/angle-150.jpg","/assets/images/360/masala-chai/angle-180.jpg","/assets/images/360/masala-chai/angle-210.jpg","/assets/images/360/masala-chai/angle-240.jpg","/assets/images/360/masala-chai/angle-270.jpg","/assets/images/360/masala-chai/angle-300.jpg","/assets/images/360/masala-chai/angle-330.jpg"]},{id:"kullhad-chai",name:"Kullhad Chai",price:30,category:"drinks",description:"Traditional clay-cup chai \u2014 earthy aroma, authentic taste.",image:"/assets/images/kullhad-chai.webp",tag:"bestseller"},{id:"coffee",name:"Coffee",price:40,category:"drinks",description:"Freshly brewed hot coffee \u2014 bold and smooth.",image:"/assets/images/coffee.webp"},{id:"cold-coffee",name:"Cold Coffee",price:60,category:"drinks",description:"Chilled blended coffee with a hint of sweetness.",image:"/assets/images/cold-coffee.webp"},{id:"besan-chila",name:"Besan Chila",price:29,category:"breakfast",description:"Crispy chickpea flour pancakes \u2014 a protein-rich morning classic.",image:"/assets/images/besan-chila.webp"},{id:"poha",name:"Poha",price:39,category:"breakfast",description:"Flattened rice with mustard, curry leaves, and peanuts.",image:"/assets/images/poha.webp",tag:"bestseller"},{id:"uttapam",name:"Uttapam",price:49,category:"breakfast",description:"Thick rice pancake topped with onion, tomato, and green chilli.",image:"/assets/images/uttapam.webp"},{id:"upma",name:"Upma",price:49,category:"breakfast",description:"Semolina cooked with vegetables and fragrant tempering.",image:"/assets/images/upma.webp"},{id:"aloo-paratha",name:"Aloo Paratha",price:39,category:"breakfast",description:"Whole wheat flatbread stuffed with spiced potato filling.",image:"/assets/images/aloo-paratha.webp",tag:"bestseller"},{id:"aloo-pyaaz-paratha",name:"Aloo Pyaaz Paratha",price:49,category:"breakfast",description:"Double-filled paratha with potato and caramelised onion.",image:"/assets/images/aloo-pyaaz-paratha.webp"},{id:"plain-maggi",name:"Plain Maggi",price:49,category:"maggi",description:"Classic Maggi noodles \u2014 the original comfort food.",image:"/assets/images/plain-maggi.webp"},{id:"veg-maggi",name:"Veg Maggi",price:59,category:"maggi",description:"Maggi noodles tossed with fresh seasonal vegetables.",image:"/assets/images/veg-maggi.webp",tag:"bestseller",cookingTime:"8-10 minutes",chefTips:"Always cook noodles al dente. Add vegetables in order of cooking time \u2014 harder veggies first.",ingredients:[{name:"Maggi Noodles",source:"Nestl\xE9 India",farmName:"Nestl\xE9 Production Facility",funFact:"Maggi was invented in Switzerland in 1896 by Julius Maggi.",season:"Year-round"},{name:"Fresh Carrots",source:"Local farmer, Dehradun",farmName:"Singh Organic Farms",funFact:"Carrots were originally purple and yellow before Dutch farmers bred the orange variety.",season:"Winter months"},{name:"Green Peas",source:"Uttar Pradesh",farmName:"Ganga Basin Farms",funFact:"Peas are technically a fruit, not a vegetable.",season:"Winter months"},{name:"Green Beans",source:"Maharashtra",farmName:"Western Ghats Organic Farms",funFact:"Green beans are unripened young pods of common beans.",season:"Summer & Monsoon"},{name:"Onions",source:"Local Dehradun markets",farmName:"Himalayan Foothill Onions",funFact:"Onions have been cultivated for over 5,000 years and were used in ancient Egypt as currency.",season:"Year-round"}],productionStory:[{id:1,title:"Gathering Fresh Vegetables",subtitle:"From local farms to your plate",description:"Every morning, we visit the local Dehradun vegetable market to select the freshest seasonal vegetables. Today we have carrots, peas, beans, and onions. Each vegetable is handpicked for quality \u2014 firm carrots, bright green peas, and onions with papery skins.",image:"/assets/images/production/veg-selection.jpg",stepNumber:1,totalSteps:5,duration:"20 minutes",tips:["Select vegetables that are in season for best flavor and price","Look for firm, unblemished produce"]},{id:2,title:"Prepping the Vegetables",subtitle:"Uniform cuts for even cooking",description:"Washing comes first \u2014 all vegetables are rinsed thoroughly. Then we chop: carrots into thin rounds, beans into small pieces, and onions into fine dice. Uniform size ensures everything cooks evenly and finishes at the same time.",image:"/assets/images/production/chopping-veggies.jpg",stepNumber:2,totalSteps:5,duration:"15 minutes",tips:["Use a sharp knife for cleaner cuts and faster prep","Keep sizes uniform \u2014 smaller pieces cook faster"]},{id:3,title:"Boiling Water & Maggi",subtitle:"Perfect al dente noodles",description:'We bring water to a rolling boil in a deep pan. Once boiling, we add the Maggi noodles (without the seasoning yet). Cook for exactly 2 minutes \u2014 al dente means "to the tooth" in Italian, and we want our noodles with a slight bite, not mushy.',image:"/assets/images/production/noodle-boiling.jpg",stepNumber:3,totalSteps:5,duration:"2 minutes boiling",tips:["Use plenty of water \u2014 at least 4 cups per packet","Do not add salt to the water (Maggi already has salt)","Set timer \u2014 overboiling ruins texture"]},{id:4,title:"Saut\xE9ing Vegetables",subtitle:"Locking in nutrients and color",description:"While noodles cook, we heat a little oil in a separate pan. Harder vegetables (carrots) go in first, followed by peas and beans after 2 minutes. Finally, onions join the party. We stir-fry for 3-4 minutes \u2014 vegetables should be tender-crisp, not mushy.",image:"/assets/images/production/stir-fry.jpg",stepNumber:4,totalSteps:5,duration:"5 minutes",tips:["High heat and quick cooking preserves nutrients and color","Don't overcrowd the pan \u2014 cook in batches if needed","Add vegetables in order of cooking time"]},{id:5,title:"Final Toss & Seasoning",subtitle:"Bringing it all together",description:"Drained noodles join the vegetables. We add the Maggi seasoning packet (and sometimes a pinch of extra pepper). Toss everything together for 30 seconds until well combined. The noodles absorb the flavors, vegetables stay bright, and everything is perfectly cooked.",image:"/assets/images/veg-maggi.webp",stepNumber:5,totalSteps:5,duration:"1 minute",tips:["Turn off heat before adding seasoning to prevent burning","Toss gently to avoid breaking noodles","Serve immediately for best texture"]}],rotationImages:["/assets/images/360/veg-maggi/angle-0.jpg","/assets/images/360/veg-maggi/angle-30.jpg","/assets/images/360/veg-maggi/angle-60.jpg","/assets/images/360/veg-maggi/angle-90.jpg","/assets/images/360/veg-maggi/angle-120.jpg","/assets/images/360/veg-maggi/angle-150.jpg","/assets/images/360/veg-maggi/angle-180.jpg","/assets/images/360/veg-maggi/angle-210.jpg","/assets/images/360/veg-maggi/angle-240.jpg","/assets/images/360/veg-maggi/angle-270.jpg","/assets/images/360/veg-maggi/angle-300.jpg","/assets/images/360/veg-maggi/angle-330.jpg"]},{id:"cheese-maggi",name:"Cheese Maggi",price:69,category:"maggi",description:"Maggi noodles topped with generous melted cheese.",image:"/assets/images/cheese-maggi.webp",tag:"bestseller"},{id:"veg-sandwich",name:"Veg Sandwich",price:79,category:"sandwich",description:"Fresh vegetables between toasted bread with chutney and cheese.",image:"/assets/images/veg-sandwich.webp"},{id:"cheese-sandwich",name:"Cheese Sandwich",price:89,category:"sandwich",description:"Grilled sandwich loaded with melted cheese \u2014 crispy outside, gooey inside.",image:"/assets/images/cheese-sandwich.webp",tag:"bestseller"},{id:"veg-pasta",name:"Veg Pasta",price:49,category:"pasta",description:"Pasta in classic red sauce with seasonal vegetables.",image:"/assets/images/veg-pasta.webp"},{id:"white-sauce-pasta",name:"White Sauce Pasta",price:69,category:"pasta",description:"Creamy b\xE9chamel pasta with Italian herbs \u2014 rich and indulgent.",image:"/assets/images/white-sauce-pasta.webp",tag:"bestseller"}],n=class t{getAll(){return s}getByCategory(e){return s.filter(a=>a.category===e)}getById(e){return s.find(a=>a.id===e)}getCategories(){return r}getFeatured(){return s.filter(e=>e.tag==="bestseller").slice(0,6)}static{this.\u0275fac=function(a){return new(a||t)}}static{this.\u0275prov=i({token:t,factory:t.\u0275fac,providedIn:"root"})}};expo